import { motion } from 'framer-motion';
import {
  X, Loader2, CheckCircle2, XCircle, Clock, Image,
  Sparkles, ShieldCheck, Star, AlertTriangle,
} from 'lucide-react';
import type { TaskStatus, BatchTask } from '../../store/useBatchStore';
import ProgressBar from '../ui/ProgressBar';

interface BatchTaskCardProps {
  task: BatchTask;
  index: number;
  onRemove: (taskId: string) => void;
}

/* ──────────────── 状态配置映射（8种状态） ──────────────── */
const STATUS_CONFIG: Record<TaskStatus, {
  label: string;
  color: string;
  glowColor: string;
  icon: React.ElementType;
  animClass: string;
}> = {
  idle: {
    label: '等待处理',
    color: 'text-studio-text-dim',
    glowColor: '',
    icon: Clock,
    animClass: '',
  },
  loading: {
    label: '读取中...',
    color: 'text-studio-accent',
    glowColor: 'shadow-glow-accent/30',
    icon: Loader2,
    animClass: 'animate-spin',
  },
  analyzing: {
    label: 'AI 分析中...',
    color: 'text-studio-warning',
    glowColor: 'shadow-glow-warning/30',
    icon: Sparkles,
    animClass: 'animate-pulse',
  },
  completed: {
    label: 'V1 完成',
    color: 'text-studio-success',
    glowColor: '',
    icon: CheckCircle2,
    animClass: '',
  },
  error: {
    label: '处理失败',
    color: 'text-red-400',
    glowColor: '',
    icon: XCircle,
    animClass: '',
  },
  reviewing: {
    label: '复查精炼中...',
    color: 'text-studio-purple',
    glowColor: 'shadow-[0_0_12px_rgba(168,85,247,0.3)]',
    icon: ShieldCheck,
    animClass: 'animate-bounce',
  },
  reviewed: {
    label: 'V2 成品',
    color: 'text-studio-purple',
    glowColor: '',
    icon: Star,
    animClass: '',
  },
  review_error: {
    label: '复查失败',
    color: 'text-orange-400',
    glowColor: '',
    icon: XCircle,
    animClass: '',
  },
};

/* ──────────────── 动画变体 ──────────────── */
const cardVariants = {
  hidden: { opacity: 0, y: 20, scale: 0.96 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    scale: 1,
    transition: {
      delay: i * 0.06,
      duration: 0.4,
      ease: [0.22, 1, 0.36, 1],
    },
  }),
};

/* ──────────────── 主组件 ──────────────── */
export default function BatchTaskCard({ task, index, onRemove }: BatchTaskCardProps) {
  const config = STATUS_CONFIG[task.status];
  const StatusIcon = config.icon;

  const isActive = task.status === 'loading' || task.status === 'analyzing' || task.status === 'reviewing';
  const isTerminal = task.status === 'completed' || task.status === 'error' || task.status === 'reviewed' || task.status === 'review_error';
  const isV1Done = task.status === 'completed' || (task.status === 'reviewed' || task.status === 'review_error');
  const isV2Done = task.status === 'reviewed';

  return (
    <motion.div
      custom={index}
      variants={cardVariants}
      initial="hidden"
      animate="visible"
      whileHover={{ y: -3, transition: { duration: 0.2 } }}
      className={`
        group relative rounded-2xl overflow-hidden cursor-default
        bg-white/[0.04] backdrop-blur-xl
        border border-white/[0.08]
        shadow-[0_4px_24px_rgba(0,0,0,0.35)]
        hover:border-white/[0.15] hover:shadow-[0_8px_32px_rgba(0,0,0,0.45)]
        transition-all duration-300 ease-out
        ${isV2Done ? 'ring-1 ring-studio-purple/25' : ''}
        ${isActive ? config.glowColor : ''}
      `}
    >
      {/* ═══════════════ 缩略图区域 ═══════════════ */}
      <div className="relative aspect-square rounded-t-2xl overflow-hidden bg-gradient-to-br from-studio-surface to-studio-panel">
        {/* 原图 / 占位 */}
        {task.originalThumbnail ? (
          <img
            src={task.originalThumbnail}
            alt={task.fileName}
            className={`w-full h-full object-cover transition-opacity duration-500 ${
              isTerminal ? 'opacity-100' : 'opacity-60'
            }`}
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <div className="p-4 rounded-2xl bg-white/[0.03] border border-white/[0.06]">
              <Image size={28} strokeWidth={1.5} className="text-studio-text-muted" />
            </div>
          </div>
        )}

        {/* 渐变遮罩 —— 从底部向上 */}
        <div className="absolute inset-x-0 bottom-0 h-[55%] bg-gradient-to-t from-black/70 via-black/30 to-transparent pointer-events-none" />

        {/* ══ 活跃状态覆盖层 ══ */}
        {isActive && (
          <div className="absolute inset-0 flex items-center justify-center">
            <motion.div
              initial={{ opacity: 0, scale: 0.7 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.7 }}
              className="flex flex-col items-center gap-2"
            >
              <div className={`w-11 h-11 rounded-xl backdrop-blur-md bg-black/50 border border-white/[0.1] flex items-center justify-center ${config.color}`}>
                <StatusIcon size={22} strokeWidth={2} className={config.animClass} />
              </div>
              <span className={`text-[10px] font-medium tracking-wide ${config.color} drop-shadow`}>
                {config.label}
              </span>
            </motion.div>
          </div>
        )}

        {/* ══ 左上角：序号 + 删除 ══ */}
        <div className="absolute top-2 left-2 z-10 flex items-center gap-1.5">
          <span className="
            w-6 h-6 rounded-lg bg-black/60 backdrop-blur-md
            flex items-center justify-center
            text-[10px] font-mono font-bold text-studio-text-dim
            border border-white/[0.08]
          ">
            {String(index + 1).padStart(2, '0')}
          </span>
          {!isActive && (
            <button
              onClick={() => onRemove(task.id)}
              className="
                w-6 h-6 rounded-lg bg-black/50 backdrop-blur-md
                flex items-center justify-center
                text-studio-text-muted hover:text-red-400 hover:bg-red-500/20
                border border-white/[0.06] hover:border-red-500/40
                transition-all duration-200 opacity-0 group-hover:opacity-100
              "
              title="移除任务"
            >
              <X size={12} strokeWidth={2} />
            </button>
          )}
        </div>

        {/* ══ 右上角：版本徽章 ══ */}
        {(task.status === 'completed' || task.status === 'error') && (
          <div className="absolute top-2 right-2 z-10">
            <span className="
              px-2 py-0.5 rounded-md text-[9px] font-mono font-bold tracking-wider uppercase
              bg-studio-accent/90 backdrop-blur-sm text-black/90
              shadow-[0_2px_8px_rgba(0,212,255,0.3)]
            ">
              V1
            </span>
          </div>
        )}

        {isV2Done && task.reviewVerdict && (
          <div className="absolute top-2 right-2 z-10 flex items-center gap-1.5">
            <span className="
              px-2 py-0.5 rounded-md text-[9px] font-mono font-bold tracking-wider uppercase
              bg-studio-purple/90 backdrop-blur-sm text-white
              shadow-[0_2px_8px_rgba(168,85,247,0.4)]
            ">
              V2
            </span>
            {/* 紫色评分星星徽章 */}
            <span className="
              flex items-center gap-0.5 px-1.5 py-0.5 rounded-full
              bg-studio-purple/80 backdrop-blur-sm text-white
              shadow-[0_2px_8px_rgba(168,85,247,0.35)]
            ">
              <Star size={10} fill="white" />
              <span className="text-[9px] font-mono font-bold leading-none">{task.reviewVerdict.overallScore}</span>
            </span>
            {/* 成品标签 */}
            <span className="
              px-1.5 py-0.5 rounded text-[8px] font-bold
              bg-emerald-500/85 backdrop-blur-sm text-white
              shadow-[0_1px_6px_rgba(16,185,129,0.3)]
            ">
              成品
            </span>
          </div>
        )}

        {/* ══ 右下角：状态图标 ══ */}
        {!isActive && isTerminal && (
          <div className="absolute bottom-2.5 right-2 z-10">
            {task.status === 'completed' && (
              <div className="w-7 h-7 rounded-xl bg-studio-success/90 backdrop-blur-sm flex items-center justify-center shadow-lg shadow-studio-success/20">
                <CheckCircle2 size={15} className="text-black" />
              </div>
            )}
            {(task.status === 'error' || task.status === 'review_error') && (
              <div className={`w-7 h-7 rounded-xl backdrop-blur-sm flex items-center justify-center shadow-lg ${
                task.status === 'error'
                  ? 'bg-red-500/90 shadow-red-500/20'
                  : 'bg-orange-500/90 shadow-orange-500/20'
              }`}>
                <XCircle size={15} className="text-white" />
              </div>
            )}
            {task.status === 'reviewed' && (
              <div className="w-7 h-7 rounded-xl bg-studio-purple/90 backdrop-blur-sm flex items-center justify-center shadow-lg shadow-studio-purple/25">
                <ShieldCheck size={15} className="text-white" />
              </div>
            )}
          </div>
        )}
      </div>

      {/* ═══════════════ 信息区域 ═══════════════ */}
      <div className="p-3 sm:p-2.5 space-y-2 sm:space-y-1.5">
        {/* ─── 文件名 ─── */}
        <p
          className="text-xs sm:text-[10px] font-mono text-studio-text truncate pr-1"
          title={task.fileName}
        >
          {task.fileName}
        </p>

        {/* ─── 状态行（图标+动画） ─── */}
        <div className={`flex items-center gap-1.5 text-[11px] sm:text-[9px] ${config.color}`}>
          <StatusIcon
            size={13}
            strokeWidth={2}
            className={`shrink-0 ${config.animClass}`}
          />
          <span className="font-medium">{config.label}</span>

          {/* 耗时 */}
          {task.duration != null && (task.status === 'completed' || task.status === 'error') && (
            <span className="ml-auto text-[10px] sm:text-[8px] text-studio-text-muted tabular-nums font-mono">
              {(task.duration / 1000).toFixed(1)}s
            </span>
          )}
          {task.v2Duration != null && (task.status === 'reviewed' || task.status === 'review_error') && (
            <span className="ml-auto text-[10px] sm:text-[8px] text-studio-text-muted tabular-nums font-mono">
              {(task.v2Duration / 1000).toFixed(1)}s
            </span>
          )}
        </div>

        {/* ─── 进度条 ─── */}
        {(task.status === 'loading' || task.status === 'analyzing') && (
          <ProgressBar
            progress={task.status === 'loading' ? task.uploadProgress : task.analysisProgress}
            label={task.currentStage || (task.status === 'loading' ? '正在读取图片...' : 'AI 分析场景...')}
            color={task.status === 'loading' ? 'bg-studio-accent' : 'bg-studio-warning'}
            size="sm"
            showPercent={false}
          />
        )}

        {task.status === 'reviewing' && (
          <ProgressBar
            progress={task.reviewProgress}
            label={task.reviewStage || '复查精炼中...'}
            color="bg-studio-purple"
            size="sm"
            showPercent={false}
          />
        )}

        {/* ─── 错误信息 ─── */}
        {task.error && (task.status === 'error' || task.status === 'review_error') && (
          <p className="text-[10px] sm:text-[8px] text-red-400/90 line-clamp-2 leading-snug bg-red-500/5 rounded-lg px-2 py-1.5 border border-red-500/10">
            {task.error}
          </p>
        )}

        {/* ═══ V1 摘要：3列网格 ═══ */}
        {task.analysisResult && isV1Done && (
          <div className="pt-2 sm:pt-1.5 border-t border-white/[0.06]">
            <div className="grid grid-cols-3 gap-1.5 sm:gap-1">
              {[
                { label: '场景', value: task.analysisResult.sceneType, dim: false },
                { label: '亮度', value: task.analysisResult.brightness, dim: false },
                { label: 'V1节点', value: String(task.commands?.length ?? 0), accent: true },
              ].map((item) => (
                <div
                  key={item.label}
                  className="bg-white/[0.03] rounded-lg px-1.5 py-1.5 sm:py-1 text-center border border-white/[0.04]"
                >
                  <p className="text-[9px] sm:text-[7px] text-studio-text-muted mb-0.5">{item.label}</p>
                  <p className={`text-[11px] sm:text-[8px] leading-tight truncate font-medium ${
                    item.accent ? 'text-studio-accent' : 'text-studio-text'
                  }`}>
                    {item.value}
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ═══ V2 结果区 ═══ */}
        {isV2Done && task.reviewVerdict && (
          <div className="pt-2 sm:pt-1.5 space-y-1.5 sm:space-y-1 border-t border-studio-purple/15">
            {/* 评分徽章 + 裁决 */}
            <div className="flex items-center gap-2 flex-wrap">
              {/* 分数根据颜色变化 */}
              <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[11px] sm:text-[9px] font-mono font-bold backdrop-blur-sm border ${
                task.reviewVerdict.overallScore >= 8
                  ? 'bg-emerald-500/15 text-emerald-400 border-emerald-500/20'
                  : task.reviewVerdict.overallScore >= 6
                    ? 'bg-studio-warning/15 text-studio-warning border-studio-warning/20'
                    : 'bg-orange-500/15 text-orange-400 border-orange-500/20'
              }`}>
                <Star size={11} fill="currentColor" />
                <span>{task.reviewVerdict.overallScore}.0</span>
              </span>

              <span className={`text-[10px] sm:text-[8px] px-2 py-0.5 rounded-md font-medium ${
                task.reviewVerdict.verdict === '通过'
                  ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/15'
                  : task.reviewVerdict.verdict === '需要修改'
                    ? 'bg-studio-warning/10 text-studio-warning border border-studio-warning/15'
                    : 'bg-orange-500/10 text-orange-400 border border-orange-500/15'
              }`}>
                {task.reviewVerdict.verdict}
              </span>
            </div>

            {/* V1 vs V2 对比 */}
            <div className="grid grid-cols-2 gap-1.5 sm:gap-1">
              <div className="bg-white/[0.02] rounded-lg px-1.5 py-1.5 sm:py-1 text-center border border-white/[0.04]">
                <p className="text-[9px] sm:text-[7px] text-studio-text-muted mb-0.5">V1 命令</p>
                <p className="text-[11px] sm:text-[8px] text-studio-text-dim tabular-nums font-mono">{task.commands?.length ?? 0}</p>
              </div>
              <div className="bg-studio-purple/[0.06] rounded-lg px-1.5 py-1.5 sm:py-1 text-center border border-studio-purple/10">
                <p className="text-[9px] sm:text-[7px] text-studio-purple/60 mb-0.5">V2 命令</p>
                <p className="text-[11px] sm:text-[8px] text-studio-purple tabular-nums font-mono font-semibold">{task.v2Commands?.length ?? 0}</p>
              </div>
            </div>

            {/* 问题列表 */}
            {task.reviewVerdict.issues.length > 0 && (
              <div className="flex items-start gap-1.5 bg-studio-warning/[0.04] rounded-lg px-2 py-1.5 border border-studio-warning/10">
                <AlertTriangle size={12} className="text-studio-warning shrink-0 mt-0.5" />
                <p className="text-[10px] sm:text-[8px] text-studio-text-dim line-clamp-2 leading-snug">
                  {task.reviewVerdict.issues[0]}
                  {task.reviewVerdict.issues.length > 1 && (
                    <span className="text-studio-warning/70 ml-1">
                      (+{task.reviewVerdict.issues.length - 1})
                    </span>
                  )}
                </p>
              </div>
            )}
          </div>
        )}
      </div>
    </motion.div>
  );
}
