import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  History,
  Trash2,
  RotateCcw,
  ChevronDown,
  Clock,
  CheckCircle2,
  XCircle,
  Image,
} from 'lucide-react';
import { useBatchStore, type BatchHistoryEntry } from '../../store/useBatchStore';

/** 格式化时间戳 */
function formatTime(timestamp: number): string {
  const d = new Date(timestamp);
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${d.getMonth() + 1}/${d.getDate()} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

/** 格式化耗时 */
function formatDuration(ms: number): string {
  if (ms < 1000) return `${ms}ms`;
  return `${(ms / 1000).toFixed(1)}s`;
}

export default function BatchHistoryPanel() {
  const { history, clearHistory, restoreFromHistory } = useBatchStore();
  const [expandedId, setExpandedId] = useState<string | null>(null);

  if (history.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-20 md:py-24">
        {/* 渐变图标容器 */}
        <div className="relative mb-5">
          <div className="w-20 h-20 md:w-24 md:h-24 rounded-2xl bg-gradient-to-br from-studio-accent/20 via-studio-purple/15 to-transparent border border-white/[0.06] backdrop-blur-sm flex items-center justify-center shadow-glow-sm">
            <History size={32} className="md:size-[36px] text-studio-accent/60" />
          </div>
          {/* 装饰光晕 */}
          <div className="absolute -inset-3 rounded-3xl bg-gradient-to-br from-studio-accent/5 to-studio-purple/5 blur-xl -z-10" />
        </div>
        <p className="text-sm md:text-base text-studio-text-muted font-medium tracking-wide">暂无历史记录</p>
        <p className="text-xs md:text-sm text-studio-text-dim/60 mt-1.5 max-w-[220px] text-center leading-relaxed">
          完成批量处理后，记录将在此处展示
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {/* 头部操作栏 */}
      <div className="flex items-center justify-between px-1">
        <div className="flex items-center gap-2.5">
          <div className="flex items-center gap-1.5">
            <History size={16} className="text-studio-accent" />
            <h3 className="text-sm font-mono text-studio-text font-semibold tracking-wide">历史记录</h3>
          </div>
          <span className="inline-flex items-center justify-center min-w-[22px] h-[22px] px-1.5 text-[11px] font-mono font-bold text-studio-accent bg-studio-accent/10 border border-studio-accent/20 rounded-full tabular-nums">
            {history.length}
          </span>
        </div>
        <button
          onClick={clearHistory}
          className="group flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg border border-red-500/25 text-red-400/80 hover:border-red-500/50 hover:text-red-300 hover:bg-red-500/[0.08] transition-all duration-200 active:scale-[0.97]"
        >
          <Trash2 size={13} className="group-hover:rotate-12 transition-transform duration-200" />
          清空全部
        </button>
      </div>

      {/* 历史列表 */}
      <div className="space-y-3">
        <AnimatePresence initial={false}>
          {history.map((entry, index) => (
            <HistoryCard
              key={entry.id}
              entry={entry}
              index={index}
              isExpanded={expandedId === entry.id}
              onToggle={() => setExpandedId(expandedId === entry.id ? null : entry.id)}
              onRestore={() => restoreFromHistory(entry.id)}
            />
          ))}
        </AnimatePresence>
      </div>
    </div>
  );
}

/* ============================================================
   HistoryCard — 单条历史记录卡片（玻璃拟态）
   ============================================================ */

function HistoryCard({
  entry,
  index,
  isExpanded,
  onToggle,
  onRestore,
}: {
  entry: BatchHistoryEntry;
  index: number;
  isExpanded: boolean;
  onToggle: () => void;
  onRestore: () => void;
}) {
  const successCount = entry.tasks.filter((t) => t.status === 'completed' || t.status === 'reviewed').length;
  const failCount = entry.tasks.filter((t) => t.status === 'error' || t.status === 'review_error').length;

  return (
    <motion.div
      initial={{ opacity: 0, y: 16, scale: 0.98 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      exit={{ opacity: 0, y: -12, scale: 0.97 }}
      transition={{ duration: 0.28, ease: [0.22, 1, 0.36, 1], delay: Math.min(index * 0.04, 0.2) }}
      className="group relative rounded-2xl bg-white/[0.03] backdrop-blur-sm border border-white/[0.06] overflow-hidden transition-colors duration-300 hover:border-studio-accent/20 hover:bg-white/[0.04]"
    >
      {/* 微妙顶部高光线 */}
      <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-studio-accent/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

      {/* 摘要行 */}
      <button
        onClick={onToggle}
        className="w-full flex items-center gap-3 sm:gap-4 p-3 sm:p-4 text-left"
      >
        {/* 缩略图网格预览 — 桌面端 5列 / 手机端 3列 */}
        <div className="grid gap-[2px] shrink-0 rounded-lg overflow-hidden border border-white/[0.04] bg-black/30 sm:w-[80px] sm:h-[50px] w-[78px] h-[52px]">
          <style>{`
            .thumb-grid-5 { grid-template-columns: repeat(5, 1fr); }
            @media (max-width: 639px) { .thumb-grid-5 { grid-template-columns: repeat(3, 1fr); } }
          `}</style>
          <div className="grid gap-[2px] w-full h-full thumb-grid-5">
            {entry.tasks.slice(0, 10).map((task, i) => (
              <div key={i} className="bg-studio-bg relative aspect-square">
                {task.originalThumbnail ? (
                  <img src={task.originalThumbnail} alt="" className="w-full h-full object-cover" loading="lazy" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <Image size={10} className="opacity-20" />
                  </div>
                )}
                {/* 状态角标 */}
                {(task.status === 'completed' || task.status === 'reviewed') && (
                  <div className="absolute bottom-0 right-0 w-1.5 h-1.5 rounded-tl-sm bg-studio-success shadow-[0_0_4px_rgba(74,222,128,0.5)]" />
                )}
                {(task.status === 'error' || task.status === 'review_error') && (
                  <div className="absolute bottom-0 right-0 w-1.5 h-1.5 rounded-tl-sm bg-red-500 shadow-[0_0_4px_rgba(239,68,68,0.5)]" />
                )}
              </div>
            ))}
          </div>
        </div>

        {/* 统计信息区 */}
        <div className="flex-1 min-w-0 py-0.5">
          {/* 时间行 */}
          <div className="flex items-center gap-1.5 mb-1.5">
            <Clock size={12} className="text-studio-text-muted/70 shrink-0" />
            <span className="text-[11px] sm:text-xs font-mono text-studio-text-dim tracking-wide">
              {formatTime(entry.timestamp)}
            </span>
          </div>
          {/* 状态统计行 */}
          <div className="flex items-center gap-1.5 flex-wrap text-[10px] sm:text-[11px]">
            <span className="text-studio-text-dim">{entry.tasks.length} 张</span>
            <span className="text-white/[0.08] select-none mx-0.5">·</span>
            <CheckCircle2 size={11} className="text-studio-success/80 shrink-0" />
            <span className="text-studio-success/90 font-mono tabular-nums">{successCount}</span>
            {failCount > 0 && (
              <>
                <XCircle size={11} className="text-red-400/80 ml-0.5 shrink-0" />
                <span className="text-red-400/90 font-mono tabular-nums">{failCount}</span>
              </>
            )}
            <span className="text-white/[0.08] select-none mx-0.5">·</span>
            <span className="text-studio-text-muted/70 font-mono">{formatDuration(entry.totalDuration)}</span>
          </div>
        </div>

        {/* 展开/收起箭头 */}
        <motion.div
          animate={{ rotate: isExpanded ? 180 : 0 }}
          transition={{ duration: 0.25, ease: 'easeInOut' }}
          className="shrink-0 p-1 rounded-md text-studio-text-muted/50 group-hover:text-studio-accent/60 transition-colors duration-200"
        >
          <ChevronDown size={16} strokeWidth={2} />
        </motion.div>
      </button>

      {/* 展开详情区域 */}
      <AnimatePresence initial={false}>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.3, ease: [0.22, 1, 0.36, 1] }}
            className="overflow-hidden"
          >
            <div className="px-3 sm:px-4 pb-4 pt-0 space-y-3">
              {/* 分隔线 */}
              <div className="h-px bg-gradient-to-r from-transparent via-white/[0.06] to-transparent" />

              {/* 任务详情网格 — 桌面端 5列 / 手机端 2-3列 */}
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-2 sm:gap-2.5">
                {entry.tasks.map((task, i) => (
                  <TaskDetailItem key={`${task.id}-${i}`} task={task} index={i} />
                ))}
              </div>

              {/* 恢复按钮 */}
              <button
                onClick={onRestore}
                className="group/btn w-full flex items-center justify-center gap-2 py-2.5 rounded-xl border border-studio-accent/25 text-studio-accent/80 hover:border-studio-accent/50 hover:text-studio-accent hover:bg-studio-accent/[0.06] transition-all duration-250 active:scale-[0.98] text-xs sm:text-sm font-mono font-medium"
              >
                <RotateCcw size={14} className="group-hover/btn:rotate-[-180deg] transition-transform duration-500" />
                恢复此批次到任务列表
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

/* ============================================================
   TaskDetailItem — 单个任务的详情展示
   ============================================================ */

function TaskDetailItem({ task, index }: { task: import('../../store/useBatchStore').BatchTask; index: number }) {
  const isSuccess = task.status === 'completed' || task.status === 'reviewed';
  const isError = task.status === 'error' || task.status === 'review_error';

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.03, duration: 0.2 }}
      className={`rounded-xl overflow-hidden border backdrop-blur-[2px] transition-colors duration-200 ${
        isSuccess
          ? 'border-studio-success/15 bg-studio-success/[0.03] hover:border-studio-success/30'
          : isError
            ? 'border-red-500/15 bg-red-500/[0.03] hover:border-red-500/30'
            : 'border-white/[0.05] bg-white/[0.02] hover:border-white/[0.1]'
      }`}
    >
      {/* 缩略图 */}
      <div className="aspect-square bg-studio-bg relative overflow-hidden">
        {task.originalThumbnail ? (
          <img
            src={task.originalThumbnail}
            alt=""
            className="w-full h-full object-cover"
            loading="lazy"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center bg-studio-bg">
            <Image size={18} className="opacity-20" />
          </div>
        )}

        {/* 左上角序号 */}
        <div className="absolute top-1 left-1.5 w-5 h-5 rounded-md bg-black/50 backdrop-blur-sm flex items-center justify-center">
          <span className="text-[9px] font-mono text-white/40 tabular-nums leading-none">
            {index + 1}
          </span>
        </div>

        {/* 右下角状态图标 */}
        <div className="absolute bottom-1 right-1.5">
          {isSuccess && (
            <CheckCircle2 size={14} className="text-studio-success drop-shadow-[0_0_4px_rgba(74,222,128,0.5)]" />
          )}
          {isError && (
            <XCircle size={14} className="text-red-400 drop-shadow-[0_0_4px_rgba(239,68,68,0.5)]" />
          )}
        </div>
      </div>

      {/* 文件名 + V状态信息 */}
      <div className="p-1.5 sm:p-2 space-y-1">
        <p className="text-[9px] sm:text-[10px] font-mono text-studio-text-dim truncate leading-tight" title={task.fileName}>
          {task.fileName}
        </p>

        {/* V1 / V2 状态标签 */}
        <div className="flex items-center gap-1 flex-wrap">
          {task.commands && task.commands.length > 0 && (
            <span className="inline-flex items-center gap-0.5 px-1 py-0.5 rounded text-[8px] sm:text-[9px] font-mono bg-studio-purple/10 text-studio-purple/80 border border-studio-purple/15">
              V1
            </span>
          )}
          {task.v2Commands && task.v2Commands.length > 0 && (
            <span className="inline-flex items-center gap-0.5 px-1 py-0.5 rounded text-[8px] sm:text-[9px] font-mono bg-studio-accent/10 text-studio-accent/80 border border-studio-accent/15">
              V2
            </span>
          )}
          {!isSuccess && !isError && (
            <span className="text-[8px] sm:text-[9px] text-studio-text-muted/50 font-mono">
              待处理
            </span>
          )}
        </div>
      </div>
    </motion.div>
  );
}
