import { useState, useCallback, useRef } from 'react';
import {
  Upload,
  Play,
  Square,
  Trash2,
  History,
  Layers,
  Clock,
  CheckCircle2,
  Loader2,
  ShieldCheck,
} from 'lucide-react';
import { useBatchStore, type BatchTask } from '../../store/useBatchStore';
import BatchTaskCard from './BatchTaskCard';
import BatchHistoryPanel from './BatchHistoryPanel';
import { analyzeAndGrade, type AutoGradeResult } from '../../ai/agnes/imageAnalyzer';
import { reviewAndRefine } from '../../ai/agnes/imageAnalyzer';

type TabType = 'tasks' | 'history';

/** 根据下载进度百分比返回对应的阶段描述 */
function getAnalysisStage(pct: number): string {
  if (pct < 15) return '正在连接 Agnes AI...';
  if (pct < 35) return 'AI 正在分析图像内容...';
  if (pct < 60) return 'AI 正在识别场景与色彩...';
  if (pct < 85) return '正在生成调色方案...';
  return '正在整理分析结果...';
}

/** 复查阶段进度描述 */
function getReviewStage(pct: number): string {
  if (pct < 20) return '首席调色师审查中...';
  if (pct < 45) return '检测过度调整...';
  if (pct < 70) return '生成精炼方案(V2)...';
  if (pct < 90) return '对比V1差异分析...';
  return '完成第二版成品...';
}

/**
 * 将 File 转换为 ImageData（用于 AI 分析）
 */
async function fileToImageData(file: File, onProgress?: (pct: number) => void): Promise<{ imageData: ImageData; thumbnail: string }> {
  const dataUrl = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.onprogress = (e: ProgressEvent) => {
      if (e.lengthComputable && e.total > 0 && onProgress) {
        onProgress(Math.round((e.loaded / e.total) * 100));
      }
    };
    reader.readAsDataURL(file);
  });

  const img = await new Promise<HTMLImageElement>((resolve, reject) => {
    const image = new Image();
    image.onload = () => resolve(image);
    image.onerror = reject;
    image.src = dataUrl;
  });

  const canvas = document.createElement('canvas');
  canvas.width = img.naturalWidth;
  canvas.height = img.naturalHeight;
  const ctx = canvas.getContext('2d', { willReadFrequently: true })!;
  ctx.drawImage(img, 0, 0);
  const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

  // 缩略图
  let tw = img.naturalWidth;
  let th = img.naturalHeight;
  const MAX_THUMB = 200;
  if (tw > MAX_THUMB || th > MAX_THUMB) {
    const s = Math.min(MAX_THUMB / tw, MAX_THUMB / th);
    tw = Math.round(tw * s);
    th = Math.round(th * s);
  }
  const thumbCanvas = document.createElement('canvas');
  thumbCanvas.width = tw;
  thumbCanvas.height = th;
  const thumbCtx = thumbCanvas.getContext('2d')!;
  thumbCtx.drawImage(img, 0, 0, tw, th);
  const thumbnail = thumbCanvas.toDataURL('image/jpeg', 0.7);

  return { imageData, thumbnail };
}

export default function BatchPanel() {
  const [activeTab, setActiveTab] = useState<TabType>('tasks');
  const abortRefs = useRef<Map<string, AbortController>>(new Map());

  const {
    tasks,
    isProcessing,
    isReviewing,
    completedCount,
    reviewedCount,
    addTasks,
    removeTask,
    clearTasks,
    updateTask,
    setProcessing,
    setReviewing,
    finishBatch,
  } = useBatchStore();

  const fileInputRef = useRef<HTMLInputElement>(null);

  /** 缓存每个任务的 ImageData（复查阶段复用，避免重复读取文件） */
  const imageDataCache = useRef<Map<string, ImageData>>(new Map());

  /**
   * 阶段1：处理单个任务 - 读取图片 + AI 分析
   */
  const processSingleTask = useCallback(async (task: BatchTask) => {
    if (!task.file) return;

    const startTime = Date.now();
    updateTask(task.id, { status: 'loading', startTime });

    try {
      // 读取文件
      updateTask(task.id, { currentStage: '正在读取图片...' });
      const { imageData } = await fileToImageData(task.file, (pct) => {
        updateTask(task.id, { uploadProgress: pct });
      });
      updateTask(task.id, { uploadProgress: 100 });

      // 缓存 ImageData 供复查使用
      imageDataCache.current.set(task.id, imageData);

      // AI 分析
      updateTask(task.id, { status: 'analyzing', currentStage: '正在连接 Agnes AI...', analysisProgress: 42 });

      const aiResult: AutoGradeResult = await analyzeAndGrade(imageData, (loaded, total) => {
        const rawPct = Math.min(loaded / Math.max(total, 1), 1);
        const mappedPct = 42 + rawPct * 51;
        updateTask(task.id, {
          analysisProgress: Math.round(mappedPct),
          currentStage: getAnalysisStage(rawPct * 100),
        });
      });

      // 完成 - 保存V1结果和完整AutoGradeResult供复查使用
      const duration = Date.now() - startTime;
      updateTask(task.id, {
        status: 'completed',
        analysisProgress: 100,
        currentStage: '第一版完成',
        analysisResult: aiResult.analysis,
        commands: aiResult.commands,
        duration,
        v1Result: aiResult,
      });
    } catch (error) {
      const duration = Date.now() - startTime;
      updateTask(task.id, {
        status: 'error',
        error: error instanceof Error ? error.message : '未知错误',
        duration,
      });
    }
  }, [updateTask]);

  /**
   * 阶段2：对单个任务进行复查精炼 - 发送V1结果回AI获取V2
   */
  const reviewSingleTask = useCallback(async (task: BatchTask) => {
    if (!task.v1Result) return;

    const cachedImageData = imageDataCache.current.get(task.id);
    if (!cachedImageData && !task.file) return;

    const reviewStartTime = Date.now();
    updateTask(task.id, { status: 'reviewing', reviewProgress: 5, reviewStage: '准备复查数据...' });

    try {
      // 如果缓存没有，重新读取文件
      let imageData = cachedImageData;
      if (!imageData && task.file) {
        const result = await fileToImageData(task.file);
        imageData = result.imageData;
        imageDataCache.current.set(task.id, imageData);
      }

      if (!imageData) throw new Error('无法获取图像数据');

      updateTask(task.id, { reviewStage: '发送给首席调色师...', reviewProgress: 10 });

      const reviewResult = await reviewAndRefine(imageData, task.v1Result, (loaded, total) => {
        const rawPct = Math.min(loaded / Math.max(total, 1), 1);
        const mappedPct = 10 + rawPct * 80;
        updateTask(task.id, {
          reviewProgress: Math.round(mappedPct),
          reviewStage: getReviewStage(rawPct * 100),
        });
      });

      const v2Duration = Date.now() - reviewStartTime;
      updateTask(task.id, {
        status: 'reviewed',
        reviewProgress: 100,
        reviewStage: '第二版完成',
        reviewVerdict: reviewResult.review,
        v2AnalysisResult: reviewResult.v2Analysis,
        v2Suggestions: reviewResult.v2Suggestions,
        v2Commands: reviewResult.v2Commands,
        v2Reasoning: reviewResult.v2Reasoning,
        v2Duration,
      });
    } catch (error) {
      const v2Duration = Date.now() - reviewStartTime;
      updateTask(task.id, {
        status: 'review_error',
        reviewStage: '复查失败',
        error: error instanceof Error ? error.message : '复查未知错误',
        v2Duration,
      });
    }
  }, [updateTask]);

  /** 开始阶段1：全部AI分析（10个并行） */
  const startAll = useCallback(async () => {
    const idleTasks = tasks.filter((t) => t.status === 'idle');
    if (idleTasks.length === 0) return;

    setProcessing(true);
    setReviewing(false);

    await Promise.all(
      idleTasks.map((task) => processSingleTask(task))
    );

    setProcessing(false);
  }, [tasks, processSingleTask, setProcessing, setReviewing]);

  /** 停止所有任务 */
  const stopAll = useCallback(() => {
    abortRefs.current.forEach((controller) => controller.abort());
    abortRefs.current.clear();

    tasks.forEach((task) => {
      if (task.status === 'loading' || task.status === 'analyzing' || task.status === 'reviewing') {
        updateTask(task.id, {
          status: task.status === 'reviewing' ? 'review_error' : 'error',
          error: '用户取消',
        });
      }
    });

    setProcessing(false);
    setReviewing(false);
  }, [tasks, updateTask, setProcessing, setReviewing]);

  /** 开始阶段2：全部复查（10个并行） */
  const startReview = useCallback(async () => {
    const completedTasks = tasks.filter((t) => t.status === 'completed');
    if (completedTasks.length === 0) return;

    setProcessing(true);
    setReviewing(true);

    await Promise.all(
      completedTasks.map((task) => reviewSingleTask(task))
    );

    setProcessing(false);
    setReviewing(false);
  }, [tasks, reviewSingleTask, setProcessing, setReviewing]);

  /** 文件选择处理 */
  const handleFilesSelected = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;
    const imageFiles = files.filter((f) => f.type.startsWith('image/'));
    if (imageFiles.length > 0) {
      await addTasks(imageFiles);
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  }, [addTasks]);

  /** 拖拽上传 */
  const [isDragOver, setIsDragOver] = useState(false);
  const dragCounter = useRef(0);

  const handleDragEnter = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current++;
    if (e.dataTransfer.types.includes('Files')) setIsDragOver(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    dragCounter.current--;
    if (dragCounter.current <= 0) {
      dragCounter.current = 0;
      setIsDragOver(false);
    }
  }, []);

  const handleDrop = useCallback(async (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragOver(false);
    dragCounter.current = 0;
    const files = Array.from(e.dataTransfer.files).filter((f) => f.type.startsWith('image/'));
    if (files.length > 0) await addTasks(files);
  }, [addTasks]);

  const idleCount = tasks.filter((t) => t.status === 'idle').length;
  const activeCount = tasks.filter((t) =>
    t.status === 'loading' || t.status === 'analyzing' || t.status === 'reviewing'
  ).length;
  const canReview = !isReviewing && !isProcessing &&
    tasks.filter((t) => t.status === 'completed').length > 0;

  return (
    <div className="flex-1 flex flex-col overflow-hidden relative">
      {/* 赛博朋克背景层 */}
      <div className="absolute inset-0 bg-gradient-to-br from-slate-950 via-slate-900 to-slate-950" />
      <div className="absolute inset-0 opacity-[0.03]"
        style={{
          backgroundImage: `radial-gradient(circle at 20% 50%, rgba(6,182,212,0.3) 0%, transparent 50%),
            radial-gradient(circle at 80% 50%, rgba(168,85,247,0.3) 0%, transparent 50%)`,
        }}
      />

      {/* 网格背景 */}
      <div className="absolute inset-0 opacity-[0.02]"
        style={{
          backgroundImage: `linear-gradient(rgba(255,255,255,.05) 1px, transparent 1px),
            linear-gradient(90deg, rgba(255,255,255,.05) 1px, transparent 1px)`,
          backgroundSize: '40px 40px'
        }}
      />

      {/* 主内容 */}
      <div className="relative z-10 flex flex-col h-full">
        {/* ═══════════════════ 顶部工具栏 ═══════════════════ */}
        <header className="shrink-0 backdrop-blur-xl bg-white/[0.03] border-b border-white/[0.06]
          px-4 sm:px-6 py-3 sm:py-4 flex items-center justify-between gap-3">
          {/* 左侧：标题 + 统计徽章 */}
          <div className="flex items-center gap-2 sm:gap-4 min-w-0">
            {/* 图标 + 标题 */}
            <div className="flex items-center gap-2 shrink-0">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-cyan-500 to-cyan-600 
                flex items-center justify-center shadow-lg shadow-cyan-500/20">
                <Layers size={16} className="text-white" strokeWidth={2} />
              </div>
              <h1 className="text-sm sm:text-base font-mono font-bold text-transparent bg-clip-text
                bg-gradient-to-r from-cyan-300 via-white to-purple-300 whitespace-nowrap hidden xs:block">
                多线程批量模式
              </h1>
            </div>

            {/* 统计信息胶囊 - 玻璃态 */}
            {tasks.length > 0 && (
              <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-full
                backdrop-blur-md bg-white/[0.04] border border-white/[0.08]
                text-[10px] sm:text-xs font-mono tracking-wide overflow-x-auto scrollbar-hide">
                <span className="text-slate-400 font-semibold">{tasks.length}/10</span>

                <span className="w-px h-3 bg-white/10" />

                {activeCount > 0 && (
                  <>
                    <Loader2 size={11} className={`animate-spin ${
                      isReviewing ? 'text-purple-400' : 'text-amber-400'
                    }`} />
                    <span className={isReviewing ? 'text-purple-400' : 'text-amber-400'}>
                      {isReviewing ? `复查${reviewedCount}` : `处理${completedCount}`}
                    </span>
                  </>
                )}

                {completedCount > 0 && !isReviewing && (
                  <>
                    <span className="w-px h-3 bg-white/10" />
                    <CheckCircle2 size={11} className="text-emerald-400" />
                    <span className="text-emerald-400">{completedCount}</span>
                  </>
                )}

                {reviewedCount > 0 && (
                  <>
                    <span className="w-px h-3 bg-white/10" />
                    <ShieldCheck size={11} className="text-violet-400" />
                    <span className="text-violet-400">{reviewedCount}</span>
                  </>
                )}

                {isReviewing && (
                  <span className="ml-0.5 text-purple-400/70 text-[9px]">(复查)</span>
                )}
              </div>
            )}
          </div>

          {/* 右侧：Tab 切换组 */}
          <div className="flex items-center gap-1 p-1 rounded-xl backdrop-blur-md bg-white/[0.03] border border-white/[0.06]">
            <button
              onClick={() => setActiveTab('tasks')}
              className={`relative px-3 sm:px-4 py-1.5 rounded-lg text-[11px] sm:text-xs font-mono
                transition-all duration-200 flex items-center gap-1.5 ${
                activeTab === 'tasks'
                  ? 'text-white'
                  : 'text-slate-500 hover:text-slate-300'
              }`}>
              {activeTab === 'tasks' && (
                <div className="absolute inset-0 rounded-lg bg-gradient-to-r from-cyan-500 to-cyan-600
                  shadow-lg shadow-cyan-500/25" />
              )}
              <Layers size={12} className="relative z-10" />
              <span className="relative z-10 hidden sm:inline">任务列表</span>
            </button>
            <button
              onClick={() => setActiveTab('history')}
              className={`relative px-3 sm:px-4 py-1.5 rounded-lg text-[11px] sm:text-xs font-mono
                transition-all duration-200 flex items-center gap-1.5 ${
                activeTab === 'history'
                  ? 'text-white'
                  : 'text-slate-500 hover:text-slate-300'
                }`}>
              {activeTab === 'history' && (
                <div className="absolute inset-0 rounded-lg bg-gradient-to-r from-violet-500 to-purple-600
                  shadow-lg shadow-violet-500/25" />
              )}
              <History size={12} className="relative z-10" />
              <span className="relative z-10 hidden sm:inline">历史</span>
            </button>
          </div>
        </header>

        {/* ═══════════════════ 主内容区 ═══════════════════ */}
        <main className="flex-1 overflow-auto p-4 sm:p-6">
          {activeTab === 'tasks' ? (
            <div className="max-w-7xl mx-auto space-y-5">
              {tasks.length === 0 ? (
                /* ══ 空状态 - 上传区域 ══ */
                <div
                  onClick={() => fileInputRef.current?.click()}
                  onDragEnter={handleDragEnter}
                  onDragLeave={handleDragLeave}
                  onDragOver={(e) => { e.preventDefault(); e.stopPropagation(); }}
                  onDrop={handleDrop}
                  className={`group cursor-pointer rounded-2xl sm:rounded-3xl border-2 border-dashed
                    transition-all duration-500 ease-out flex flex-col items-center justify-center
                    min-h-[420px] sm:min-h-[480px] relative overflow-hidden ${
                    isDragOver
                      ? 'border-cyan-400 scale-[1.01] shadow-2xl shadow-cyan-500/15'
                      : 'border-white/[0.08] hover:border-cyan-500/30'
                  }`}
                >
                  {/* 动态背景 */}
                  <div className={`absolute inset-0 transition-all duration-500 ${
                    isDragOver
                      ? 'bg-gradient-to-br from-cyan-500/[0.06] via-purple-500/[0.04] to-cyan-500/[0.06]'
                      : 'bg-white/[0.01] group-hover:bg-white/[0.02]'
                  }`} />

                  {/* 扫描线动画 */}
                  {isDragOver && (
                    <div className="absolute inset-x-0 top-0 h-px bg-gradient-to-r from-transparent via-cyan-400 to-transparent animate-scan" />
                  )}

                  {/* 内容 */}
                  <div className="relative z-10 flex flex-col items-center max-w-sm mx-auto px-6">
                    {/* 中心图标容器 */}
                    <div className={`w-20 h-20 sm:w-24 sm:h-24 rounded-2xl sm:rounded-3xl
                      flex items-center justify-center mb-6 transition-all duration-500 ${
                        isDragOver
                          ? 'bg-gradient-to-br from-cyan-500/20 to-purple-500/20 scale-110 shadow-xl shadow-cyan-500/20'
                          : 'bg-white/[0.03] border border-white/[0.06] group-hover:border-cyan-500/20 group-hover:bg-white/[0.05]'
                      }`}>
                      <Upload size={isDragOver ? 36 : 32}
                        className={`transition-all duration-500 ${
                          isDragOver
                            ? 'text-cyan-400 animate-bounce'
                            : 'text-slate-500 group-hover:text-cyan-400/80'
                        }`}
                        strokeWidth={1.5}
                      />
                    </div>

                    {/* 标题文字 */}
                    <p className="text-base sm:text-lg font-medium text-white mb-2 text-center">
                      {isDragOver ? '释放以上传图片' : '点击或拖拽图片到此处'}
                    </p>
                    <p className="text-xs sm:text-sm text-slate-500 mb-6 text-center leading-relaxed">
                      支持同时选择最多 <span className="text-cyan-400 font-mono font-semibold">10</span> 张图片，
                      将并行处理以获得最佳效率
                    </p>

                    {/* 特性标签行 */}
                    <div className="flex flex-wrap items-center justify-center gap-2 sm:gap-3">
                      {[
                        { icon: Clock, label: '10任务并发', color: 'text-cyan-400' },
                        { icon: null, label: '自动缩略图', color: 'text-emerald-400' },
                        { icon: null, label: 'AI调色+复查', color: 'text-violet-400' },
                      ].map((item, i) => (
                        <span key={i}
                          className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full
                            bg-white/[0.03] border border-white/[0.06]
                            text-[10px] sm:text-xs font-mono text-slate-400">
                          {item.icon && <item.icon size={11} className={item.color} />}
                          <span className={i === 2 ? item.color : ''}>{item.label}</span>
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              ) : (
                /* ══ 任务视图 ══ */
                <>
                  {/* 操作按钮行 */}
                  <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-3">
                    {/* 左侧按钮组 */}
                    <div className="flex items-center gap-2">
                      <button
                        onClick={() => fileInputRef.current?.click()}
                        disabled={isProcessing}
                        className="flex items-center gap-2 px-4 py-2.5 text-xs font-mono rounded-xl
                          backdrop-blur-md bg-white/[0.04] border border-white/[0.08]
                          text-slate-300 hover:border-cyan-500/40 hover:text-cyan-400
                          hover:bg-white/[0.06] transition-all duration-200
                          disabled:opacity-40 disabled:cursor-not-allowed disabled:hover:border-white/[0.08] disabled:hover:text-slate-300">
                        <Upload size={14} />
                        <span>添加图片</span>
                      </button>
                      <button
                        onClick={clearTasks}
                        disabled={isProcessing}
                        className="flex items-center gap-2 px-4 py-2.5 text-xs font-mono rounded-xl
                          backdrop-blur-md bg-red-500/[0.04] border border-red-500/15
                          text-red-400/80 hover:bg-red-500/[0.08] hover:border-red-500/30
                          hover:text-red-400 transition-all duration-200
                          disabled:opacity-40 disabled:cursor-not-allowed">
                        <Trash2 size={14} />
                        <span className="hidden sm:inline">清空</span>
                      </button>
                    </div>

                    {/* 右侧操作按钮组 */}
                    <div className="flex items-center gap-2 flex-wrap">
                      {!isProcessing && !isReviewing && idleCount > 0 && (
                        <button
                          onClick={startAll}
                          className="flex items-center gap-2 px-5 py-2.5 text-xs font-mono font-semibold rounded-xl
                            bg-gradient-to-r from-cyan-500 to-cyan-600 text-white
                            shadow-lg shadow-cyan-500/30 hover:shadow-cyan-500/50 hover:scale-[1.02]
                            transition-all duration-200 active:scale-[0.98]">
                          <Play size={13} fill="currentColor" />
                          全部开始
                          <span className="px-1.5 py-0.5 rounded-md bg-white/20 text-[10px]">{idleCount}</span>
                        </button>
                      )}

                      {!isProcessing && !isReviewing && canReview && (
                        <button
                          onClick={startReview}
                          className="flex items-center gap-2 px-5 py-2.5 text-xs font-mono font-semibold rounded-xl
                            bg-gradient-to-r from-violet-500 to-purple-600 text-white
                            shadow-lg shadow-violet-500/30 hover:shadow-violet-500/50 hover:scale-[1.02]
                            transition-all duration-200 active:scale-[0.98]">
                          <ShieldCheck size={13} />
                          开始复查
                          <span className="px-1.5 py-0.5 rounded-md bg-white/20 text-[10px]">{completedCount}</span>
                        </button>
                      )}

                      {(isProcessing || isReviewing) && (
                        <button
                          onClick={stopAll}
                          className="flex items-center gap-2 px-5 py-2.5 text-xs font-mono font-semibold rounded-xl
                            bg-gradient-to-r from-red-500/90 to-rose-600/90 text-white
                            shadow-lg shadow-red-500/25 hover:shadow-red-500/40 hover:scale-[1.02]
                            transition-all duration-200 active:scale-[0.98]">
                          <Square size={13} fill="currentColor" />
                          停止全部
                        </button>
                      )}

                      {!isProcessing && !isReviewing && reviewedCount > 0 && (
                        <button
                          onClick={finishBatch}
                          className="flex items-center gap-2 px-4 py-2.5 text-xs font-mono rounded-xl
                            backdrop-blur-md bg-emerald-500/[0.06] border border-emerald-500/20
                            text-emerald-400 hover:bg-emerald-500/[0.12] hover:border-emerald-500/35
                            transition-all duration-200">
                          <CheckCircle2 size={13} />
                          <span className="hidden sm:inline">存入历史</span>
                        </button>
                      )}
                    </div>
                  </div>

                  {/* 阶段提示条 - V1完成待复查 */}
                  {completedCount > 0 && !isReviewing && reviewedCount === 0 && !isProcessing && (
                    <div className="relative overflow-hidden rounded-2xl
                      bg-gradient-to-r from-violet-500/10 via-purple-500/10 to-fuchsia-500/10
                      border border-violet-500/20 px-5 py-3.5 flex items-center gap-3">
                      {/* 光晕效果 */}
                      <div className="absolute left-0 top-1/2 -translate-y-1/2 w-32 h-full
                        bg-gradient-to-r from-violet-500/20 to-transparent blur-sm" />

                      <div className="relative z-10 w-8 h-8 rounded-lg bg-violet-500/20
                        flex items-center justify-center shrink-0">
                        <ShieldCheck size={16} className="text-violet-400" strokeWidth={2} />
                      </div>
                      <div className="relative z-10 flex-1 min-w-0">
                        <p className="text-xs sm:text-sm text-slate-200 leading-relaxed">
                          第一版已完成！点击
                          <strong className="text-violet-400 mx-1 font-mono">开始复查</strong>
                          将结果发给首席调色师进行专业审查，生成更精炼的第二版成品
                        </p>
                      </div>
                    </div>
                  )}

                  {/* 阶段提示条 - 复查进行中 */}
                  {isReviewing && (
                    <div className="relative overflow-hidden rounded-2xl
                      bg-gradient-to-r from-violet-500/10 via-purple-500/10 to-fuchsia-500/10
                      border border-violet-500/25 px-5 py-3.5 flex items-center gap-3">
                      {/* 脉冲光晕动画 */}
                      <div className="absolute left-0 top-1/2 -translate-y-1/2 w-40 h-full
                        bg-gradient-to-r from-violet-500/30 to-transparent blur-md animate-pulse" />

                      <div className="relative z-10 w-8 h-8 rounded-lg bg-violet-500/20
                        flex items-center justify-center shrink-0">
                        <Loader2 size={16} className="text-violet-400 animate-spin" strokeWidth={2} />
                      </div>
                      <div className="relative z-10 flex-1 min-w-0">
                        <p className="text-xs sm:text-sm text-slate-200 leading-relaxed">
                          正在进行复查精炼...
                          <span className="text-violet-400 ml-2 font-mono font-semibold tabular-nums">
                            {reviewedCount}/{completedCount}
                          </span>
                          已生成第二版成品
                        </p>
                        {/* 进度条 */}
                        <div className="mt-2 h-1 rounded-full bg-white/[0.06] overflow-hidden">
                          <div
                            className="h-full rounded-full bg-gradient-to-r from-violet-500 to-fuchsia-500
                              transition-all duration-500 ease-out"
                            style={{ width: `${(reviewedCount / completedCount) * 100}%` }}
                          />
                        </div>
                      </div>
                    </div>
                  )}

                  {/* ══ 任务网格 ══ */}
                  <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-3 sm:gap-4">
                    {tasks.map((task, index) => (
                      <BatchTaskCard
                        key={task.id}
                        task={task}
                        index={index}
                        onRemove={removeTask}
                      />
                    ))}

                    {/* 空位占位符 */}
                    {Array.from({ length: 10 - tasks.length }).map((_, i) => (
                      <div
                        key={`empty-${i}`}
                        onClick={() => fileInputRef.current?.click()}
                        className="group/placeholder rounded-2xl border border-dashed border-white/[0.06]
                          hover:border-cyan-500/25 transition-all duration-300
                          aspect-square flex flex-col items-center justify-center cursor-pointer
                          backdrop-blur-sm bg-white/[0.01] hover:bg-white/[0.03]
                          min-h-[180px] sm:min-h-[220px]">
                        <div className="w-10 h-10 rounded-xl bg-white/[0.03] border border-white/[0.06]
                          flex items-center justify-center mb-2
                          group-hover/placeholder:border-cyan-500/20 group-hover/placeholder:bg-cyan-500/[0.05]
                          transition-all duration-300">
                          <PlusIcon size={18}
                            className="text-slate-600 group-hover/placeholder:text-cyan-400/70 transition-colors duration-300"
                          />
                        </div>
                        <span className="text-[9px] font-mono text-slate-700
                          group-hover/placeholder:text-cyan-500/40 transition-colors duration-300">
                          #{tasks.length + i + 1}
                        </span>
                      </div>
                    ))}
                  </div>
                </>
              )}

              {/* 隐藏的文件 input */}
              <input
                ref={fileInputRef}
                type="file"
                accept="image/*"
                multiple
                className="hidden"
                onChange={handleFilesSelected}
              />
            </div>
          ) : (
            /* ══ 历史面板 ══ */
            <div className="max-w-4xl mx-auto">
              <BatchHistoryPanel />
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

function PlusIcon({ size, className }: { size: number; className?: string }) {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24"
      fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
      className={className}>
      <line x1="12" y1="5" x2="12" y2="19"></line>
      <line x1="5" y1="12" x2="19" y2="12"></line>
    </svg>
  );
}
